<script setup lang="ts">
import{computed,onMounted,ref}from"vue";import{useRoute}from"vue-router";import{Clock3}from"lucide-vue-next";import{api,type Order}from"../api";import{cancelOrder}from"../actions";import PageHeader from"../components/PageHeader.vue";
const route=useRoute(),order=ref<Order>(),message=ref("");const status:Record<string,string>={pending_payment:"待取号",paid:"已预约",confirmed:"待就诊",completed:"已完成",cancelled:"已取消",refunded:"已退款",expired:"已过期"};const cancellable=computed(()=>order.value&&["pending_payment","paid","confirmed"].includes(order.value.status));async function load(){order.value=await api.order(Number(route.params.id))}onMounted(load);async function cancel(){if(!confirm("确认取消本次预约？"))return;try{await cancelOrder(Number(route.params.id));await load()}catch(e){message.value=e instanceof Error?e.message:"取消失败"}}
</script>
<template><main v-if="order" class="order-detail"><PageHeader title="预约挂号详情"/><div class="status-band"><Clock3/>{{status[order.status]}}</div><section><dl><dt>姓名</dt><dd>{{order.personName}}</dd><dt>手机号</dt><dd>{{order.personPhone}}</dd></dl></section><section><dl><dt>预约医生</dt><dd>{{order.doctorName}}　{{order.doctorTitle}}</dd><dt>就诊医院</dt><dd>{{order.hospitalName}}</dd><dt>就诊科室</dt><dd>{{order.departmentName}}</dd><dt>就诊时间</dt><dd>{{order.visitDate}}　{{order.period}}</dd><dt>挂号费用</dt><dd class="price">{{order.amount}}元</dd><dt>预约单号</dt><dd>{{order.orderNo}}</dd></dl></section><div class="detail-note"><b>*相关说明</b><p>请于就诊当日持患者本人身份证或医保卡到医院取号，具体费用以医院当天收取为准。</p></div><p v-if="message" class="form-message center">{{message}}</p><button v-if="cancellable" class="feedback-submit" @click="cancel">取消预约</button></main></template>
